+        assert!(matches!(
+            validate_canonical_id(".test"),
+            Err(IdValidationError::InvalidStartChar { ch: '.' })
+        ));
+        assert!(matches!(
+            validate_canonical_id("-test"),
+            Err(IdValidationError::InvalidStartChar { ch: '-' })
+        ));
+    }
+
+    #[test]
